############################################################ # Load Macros ############################################################ loadMacros( "PGstandard.pl", "PGML.pl", "AnswerFormatHelp.pl", "niceTables.pl", "PGlateximage.pl", "scaffold.pl", "PCCmacros.pl", "parserNumberWithUnits.pl", "Pd.pl", "PGcourse.pl", ); COMMENT('Authored in PreTeXt'); COMMENT('This problem is scaffolded with multiple parts');
