############################################################ # PG Setup Code ############################################################ @x=(2002..2025); @y=(540400,546000,551700,557300,562900,568600,574200,579800,585500,595600,604500,610300,621000,631900,643100,648200,651200,654400,653200,642800,636100,634300,635700,631400); %f=map{$x[$_] => $y[$_]}(0..23); @yr=num_sort(random_subset(4,@x)); $n=[ {name => 'people'}, {name => 'person',conversion => {factor => 1,people => 1}}, {name => 'ppl',conversion => {factor => 1,people => 1}}, {name => 'year',conversion => {factor => 365*24*60*60,s => 1}}, {name => 'years',conversion => {factor => 365*24*60*60,s => 1}}, {name => 'yr',conversion => {factor => 365*24*60*60,s => 1}}, {name => 'yrs',conversion => {factor => 365*24*60*60,s => 1}}, {name => 'y',conversion => {factor => 365*24*60*60,s => 1}} ]; @r=map{Real(($f{$yr[2*$_+1]}-$f{$yr[2*$_]})/($yr[2*$_+1]-$yr[2*$_]))}(0,1); @r=map{NumberWithUnits("$_ people/yr",{newUnit => $n})}(@r); Context("Interval"); $d=List('[2019,2020],[2020,2021],[2021,2022],[2022,2023],[2024,2025]'); $p=join(' ',(map{"($x[$_],$y[$_])"}(0..23))); $s=Interval('[2006,2016]'); $t=NumberWithUnits(($y[14]-$y[4])/10,"people/yr",{newUnit => $n});
$image_1 = createLaTeXImage(); $image_1->addToPreamble(latexImagePreamble()); $image_1->BEGIN_LATEX_IMAGE \begin{tikzpicture} \begin{axis}[ xmin=2000, xmax=2025, xtick={2000,2005,...,2025}, xlabel={year}, ymin=500000, ymax=700000, ytick={500000,550000,...,700000}, ylabel={population}, /pgf/number format/.cd, use comma, 1000 sep={}, axis y discontinuity=crunch, width=\orccaprintwidth, height=0.33\orccaprintwidth, axis line style={->}, ] \addplot[soliddot]coordinates{$p}; \end{axis} \end{tikzpicture}
