BEGIN_PGML This table gives population estimates for Portland, Oregon from 2002 through 2025, gathered from [@htmlLink("https://worldpopulationreview.com/us-cities/oregon/portland","https://worldpopulationreview.com/us-cities/oregon/portland","TARGET='_blank'")@]*.
>> [@DataTable( [ [[PGML('Year'), rowbottom => '2', midrule => '1',], PGML('Population'), PGML('Year'), PGML('Population'), PGML('Year'), PGML('Population'), ], [PGML('2002'), PGML('540400'), PGML('2010'), PGML('585500'), PGML('2018'), PGML('651200'), ], [PGML('2003'), PGML('546000'), PGML('2011'), PGML('595600'), PGML('2019'), PGML('654400'), ], [PGML('2004'), PGML('551700'), PGML('2012'), PGML('604500'), PGML('2020'), PGML('653200'), ], [PGML('2005'), PGML('557300'), PGML('2013'), PGML('610300'), PGML('2021'), PGML('642800'), ], [PGML('2006'), PGML('562900'), PGML('2014'), PGML('621000'), PGML('2022'), PGML('636100'), ], [PGML('2007'), PGML('568600'), PGML('2015'), PGML('631900'), PGML('2023'), PGML('634300'), ], [PGML('2008'), PGML('574200'), PGML('2016'), PGML('643100'), PGML('2024'), PGML('635700'), ], [PGML('2009'), PGML('579800'), PGML('2017'), PGML('648200'), PGML('2025'), PGML('631400'), ], ], align => 'rl!{\vrule width 0.07em}rl!{\vrule width 0.07em}rl', valign => 'middle',);@]* <<
>> [@image(insertGraph($image_1), width=>450)@]* <<
END_PGML
############################################################ # Scaffold ############################################################ Scaffold::Begin(numbered => 1,is_open => "correct_or_first_incorrect",can_open => always,);
############################################################ # Section ############################################################ Section::Begin("");
BEGIN_PGML Find the rate of change in Portland population between [$yr[0]] and [$yr[1]].
[@KeyboardInstructions('You can type the unit as [|people/yr|]*.')@]**
[_]{$r[0]}{10}
END_PGML
############################################################ # Solution ############################################################
BEGIN_PGML_SOLUTION To find the rate of change between [$yr[0]] and [$yr[1]], calculate
[``` \frac{[$f{$yr[1]}]-[$f{$yr[0]}]}{[$yr[1]]-[$yr[0]]}=[$r[0]] \text{.}```]
END_PGML_SOLUTION
Section::End();
############################################################ # Section ############################################################ Section::Begin("");
BEGIN_PGML And what was the rate of change between [$yr[2]] and [$yr[3]]?
[_]{$r[1]}{10}
END_PGML
############################################################ # Solution ############################################################
BEGIN_PGML_SOLUTION To find the rate of change between [$yr[2]] and [$yr[3]], calculate
[``` \frac{[$f{$yr[3]}]-[$f{$yr[2]}]}{[$yr[3]]-[$yr[2]]}=[$r[1]] \text{.}```]
END_PGML_SOLUTION
Section::End();
############################################################ # Section ############################################################ Section::Begin("");
BEGIN_PGML List all the year-long intervals where there is a negative rate of change.
[@KeyboardInstructions('(For example, you might answer with [|[2000,2001], [2001,2002]|]* if you think those are the year-long intervals where there is a negative rate of change.)')@]**
[_]{$d}{20}
END_PGML
############################################################ # Solution ############################################################
BEGIN_PGML_SOLUTION The rate of change is negative for the years starting in 2003, 2019, and 2020, and no other years. These are the only years in the data table where the population goes down the next year. So the intervals are [$d].
END_PGML_SOLUTION
Section::End();
############################################################ # Section ############################################################ Section::Begin("");
BEGIN_PGML Over which decade was the rate of change highest?
[@KeyboardInstructions('(For example, you might answer with [|[2000,2010]|]* if you think that is the decade with the highest rate of change.)')@]**
[_]{$s}{20}
END_PGML
############################################################ # Solution ############################################################
BEGIN_PGML_SOLUTION The steepest rate of change over a ten-year period was from 2006 to 2016. To find this, calculate each of the rates of change from 2000 to 2010, from 2001 to 2011, and so on. Although looking at the graph, you can see that some rates of change are not as steep as others and narrow down the search.
>> [@image(insertGraph($image_2), width=>450)@]* <<
END_PGML_SOLUTION
Section::End();
############################################################ # Section ############################################################ Section::Begin("");
BEGIN_PGML What was that rate of change?
[@KeyboardInstructions('You can type the unit as [|people/yr|]*.')@]**
[_]{$t}{10}
END_PGML
############################################################ # Solution ############################################################
BEGIN_PGML_SOLUTION Between 2006 and 2016:
[``` \frac{[$y[16]] - [$y[6]]}{2016 - 2006} = [$t] ```]
END_PGML_SOLUTION
Section::End();
